  ('medical-tech-moex-04604', 'medical-tech', 'medical-tech-moex-111-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '某位女士得知有個同父異母的姊姊仍健在，但卻出現兩位婦女聲稱是這位女士同父異母的姊姊。此時可藉由 分析那一條染色體上的STR快速鑑別其親生姊妹關係？', '["1號染色體", "21號染色體", "X染色體", "Y染色體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:20+00:00", "source_pdf_sha1": "8b19c38cd34e", "answer_pdf_sha1": "1a485e4af2a9", "source_family": "moex-gov-tw", "moex": {"exam_code": "111020", "c": "308", "s": "33", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "111", "exam_name": "111年第一次專技人員高等考試醫師牙醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 73, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
